import{_ as e,o as t,c as l,a5 as i}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：PCS LCL 滤波器与有源阻尼","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：PCS LCL 滤波器与有源阻尼","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0045-pcs-lcl-filter-active-damping.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/pcs/lcl-filter-active-damping.md","filePath":"content/power/concepts/pcs/lcl-filter-active-damping.md","lastUpdated":null}'),s={name:"content/power/concepts/pcs/lcl-filter-active-damping.md"};function c(r,a,o,n,p,d){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="概念-pcs-lcl-滤波器与有源阻尼" tabindex="-1">概念：PCS LCL 滤波器与有源阻尼 <a class="header-anchor" href="#概念-pcs-lcl-滤波器与有源阻尼" aria-label="Permalink to &quot;概念：PCS LCL 滤波器与有源阻尼&quot;">​</a></h1><p>本页是 <code>lessons/0045-pcs-lcl-filter-active-damping.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>LCL 滤波器（LCL filter）由变流器侧电感、滤波电容和电网侧电感组成。有源阻尼（active damping）用反馈或数字滤波抑制 LCL 谐振。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>PCS 并网电流谐波要求高。LCL 高频衰减强，但谐振峰会影响电流环稳定性。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>f_res = 1 / (2*pi) * sqrt((L1 + L2) / (L1 * L2 * Cf))</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>扫频比较 L 与 LCL，再加入电容电流反馈观察谐振峰下降。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能写出谐振频率影响因素。</li><li>能解释有源阻尼为什么需要额外反馈。</li><li>能区分逆变器侧电流和电网侧电流。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>PCS 并网电流控制通常反馈哪一路电流？LCL 阻尼入口在哪里？</p>',14)])])}const m=e(s,[["render",c]]);export{u as __pageData,m as default};
